package com.example.biometricauth

import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.text.InputType
import android.view.View
import android.widget.Button
import android.widget.EditText
import android.widget.ProgressBar
import android.widget.TextView
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AlertDialog
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat

object AuthPrefs {
    private const val PREFS_NAME = "auth_prefs"
    private const val KEY_AUTHENTICATED = "authenticated"

    fun prefs(context: Context): SharedPreferences =
        context.getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

    fun isAuthenticated(context: Context): Boolean =
        prefs(context).getBoolean(KEY_AUTHENTICATED, false)

    fun setAuthenticated(context: Context, value: Boolean) {
        prefs(context).edit().putBoolean(KEY_AUTHENTICATED, value).apply()
    }

    fun clear(context: Context) {
        prefs(context).edit().clear().apply()
    }
}

class LoginActivity : AppCompatActivity() {

    private lateinit var statusText: TextView
    private lateinit var passwordInput: EditText
    private lateinit var loginButton: Button
    private lateinit var biometricButton: Button
    private lateinit var progress: ProgressBar

    private val enrollLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) {
        maybeStartBiometric()
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        statusText = findViewById(R.id.statusText)
        passwordInput = findViewById(R.id.passwordInput)
        loginButton = findViewById(R.id.loginButton)
        biometricButton = findViewById(R.id.biometricButton)
        progress = findViewById(R.id.progress)

        if (AuthPrefs.isAuthenticated(this)) {
            goHome()
            return
        }

        passwordInput.inputType = InputType.TYPE_CLASS_TEXT or InputType.TYPE_TEXT_VARIATION_PASSWORD

        loginButton.setOnClickListener {
            doPasswordLogin()
        }

        biometricButton.setOnClickListener {
            maybeStartBiometric(force = true)
        }

        maybeStartBiometric()
    }

    private fun maybeStartBiometric(force: Boolean = false) {
        val biometricManager = BiometricManager.from(this)
        val authenticators = BiometricManager.Authenticators.BIOMETRIC_STRONG or
            BiometricManager.Authenticators.BIOMETRIC_WEAK

        when (biometricManager.canAuthenticate(authenticators)) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                biometricButton.visibility = View.VISIBLE
                if (!force) {
                    startBiometricPrompt()
                } else {
                    startBiometricPrompt()
                }
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                biometricButton.visibility = View.VISIBLE
                statusText.text = getString(R.string.biometric_not_enrolled)
                if (force) {
                    val enrollIntent = Intent(android.provider.Settings.ACTION_BIOMETRIC_ENROLL).apply {
                        putExtra(
                            android.provider.Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED,
                            authenticators
                        )
                    }
                    enrollLauncher.launch(enrollIntent)
                }
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE,
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                biometricButton.visibility = View.GONE
                statusText.text = getString(R.string.biometric_unavailable)
            }
            else -> {
                biometricButton.visibility = View.GONE
                statusText.text = getString(R.string.biometric_unavailable)
            }
        }
    }

    private fun startBiometricPrompt() {
        setLoading(false)
        statusText.text = getString(R.string.biometric_prompt_hint)

        val executor = ContextCompat.getMainExecutor(this)
        val prompt = BiometricPrompt(
            this,
            executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    AuthPrefs.setAuthenticated(this@LoginActivity, true)
                    goHome()
                }

                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    statusText.text = errString
                    showPasswordFallbackDialog(
                        title = getString(R.string.use_password_title),
                        message = getString(R.string.use_password_message)
                    )
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    statusText.text = getString(R.string.biometric_failed_try_password)
                }
            }
        )

        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle(getString(R.string.biometric_title))
            .setSubtitle(getString(R.string.biometric_subtitle))
            .setDescription(getString(R.string.biometric_description))
            .setNegativeButtonText(getString(R.string.use_password))
            .build()

        prompt.authenticate(promptInfo)
    }

    private fun showPasswordFallbackDialog(title: String, message: String) {
        AlertDialog.Builder(this)
            .setTitle(title)
            .setMessage(message)
            .setPositiveButton(R.string.use_password) { d, _ ->
                d.dismiss()
                passwordInput.requestFocus()
            }
            .setNegativeButton(android.R.string.cancel) { d, _ ->
                d.dismiss()
            }
            .show()
    }

    private fun doPasswordLogin() {
        val password = passwordInput.text?.toString().orEmpty()
        if (password.isBlank()) {
            statusText.text = getString(R.string.password_empty)
            return
        }

        setLoading(true)

        passwordInput.postDelayed({
            setLoading(false)
            val ok = password == "password123"
            if (ok) {
                AuthPrefs.setAuthenticated(this, true)
                goHome()
            } else {
                statusText.text = getString(R.string.password_incorrect)
            }
        }, 450)
    }

    private fun setLoading(loading: Boolean) {
        progress.visibility = if (loading) View.VISIBLE else View.GONE
        loginButton.isEnabled = !loading
        biometricButton.isEnabled = !loading
        passwordInput.isEnabled = !loading
    }

    private fun goHome() {
        startActivity(Intent(this, HomeActivity::class.java))
        finish()
    }
}

class HomeActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_home)

        if (!AuthPrefs.isAuthenticated(this)) {
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
            return
        }

        findViewById<Button>(R.id.logoutButton)?.setOnClickListener {
            AuthPrefs.clear(this)
            startActivity(Intent(this, LoginActivity::class.java))
            finish()
        }
    }
}